#include "qp/execution/execution_simulator.hpp"
#include <variant>
#include <cmath>
namespace qp::execution { ExecutionSimulator::ExecutionSimulator(const CommissionModel& c,const SlippageModel& s,ExecutionSimulatorConfig cfg): commission_model_(c), slippage_model_(s), config_(cfg){} Result<std::optional<Fill>> ExecutionSimulator::execute(const Order& order,const ExecutionContext& ctx) const { auto ok=order.validate(); if(!ok) return Err<std::optional<Fill>>(ok.error()); if(!std::isfinite(config_.max_participation_rate)||config_.max_participation_rate<0.0) return Err<std::optional<Fill>>(Error{ErrorCode::InvalidArgument,"max_participation_rate must be finite and non-negative"}); auto mdok=data::validate(ctx.market_data); if(!mdok) return Err<std::optional<Fill>>(mdok.error()); if(data::symbol(ctx.market_data)!=order.symbol) return Ok(std::optional<Fill>{}); double ref=data::reference_price(ctx.market_data); Quantity qty=order.quantity; if(std::holds_alternative<data::OhlcvBar>(ctx.market_data)){ const auto& b=std::get<data::OhlcvBar>(ctx.market_data); double cap=b.volume.value*config_.max_participation_rate; if(qty.value>cap){ if(config_.reject_if_insufficient_bar_volume) return Ok(std::optional<Fill>{}); if(config_.allow_partial_fills) qty=Quantity{cap}; } } SlippageInput sin{order.symbol,order.side,qty,Price{ref},std::nullopt,std::nullopt}; if(std::holds_alternative<data::Quote>(ctx.market_data)) sin.quote=std::get<data::Quote>(ctx.market_data); if(std::holds_alternative<data::Trade>(ctx.market_data)) sin.last_trade=std::get<data::Trade>(ctx.market_data); auto slip=slippage_model_.apply(sin); if(!slip) return Err<std::optional<Fill>>(slip.error()); if(order.type==OrderType::Limit && order.limit_price){ if(order.side==OrderSide::Buy && slip.value().fill_price.value>order.limit_price->value) return Ok(std::optional<Fill>{}); if(order.side==OrderSide::Sell && slip.value().fill_price.value<order.limit_price->value) return Ok(std::optional<Fill>{}); } double comm=commission_model_.calculate(CommissionInput{order.symbol,order.side,qty,slip.value().fill_price}); Fill f{order.id,order.symbol,order.side,ctx.ts,qty,slip.value().fill_price,comm,slip.value().slippage_amount}; auto fok=f.validate(); if(!fok) return Err<std::optional<Fill>>(fok.error()); return Ok(std::optional<Fill>{f}); } }
